#!/usr/bin/env python3
from pathlib import Path

ROOT = Path.cwd()

required = [
    "package.json",
    "app",
    "lib",
    "data/matches.json",
    "data/predictions.json",
    "data/players.json",
]
for rel in required:
    if not (ROOT / rel).exists():
        raise FileNotFoundError(f"No encuentro {rel}. Ejecuta este script desde la raíz del proyecto mundial-porra-2026.")

files = {
    "lib/footballData.ts": 'import matchesJson from "@/data/matches.json";\nimport type { Match, MatchResult } from "@/lib/types";\n\nconst API_URL = "https://api.football-data.org/v4/competitions/WC/matches";\nconst SEASON = "2026";\n\ntype FootballDataMatch = {\n  id: number;\n  utcDate: string;\n  status: string;\n  matchday?: number;\n  group?: string | null;\n  homeTeam: {\n    name: string;\n    shortName?: string;\n    tla?: string;\n  };\n  awayTeam: {\n    name: string;\n    shortName?: string;\n    tla?: string;\n  };\n  score: {\n    fullTime: {\n      home: number | null;\n      away: number | null;\n    };\n    halfTime?: {\n      home: number | null;\n      away: number | null;\n    };\n  };\n};\n\ntype FootballDataResponse = {\n  matches?: FootballDataMatch[];\n  message?: string;\n  errorCode?: number;\n};\n\nexport type ApiResultsPayload = {\n  results: Record<string, MatchResult>;\n  updatedAt: string;\n  source: "football-data";\n  error?: string;\n  matchedFixtures: number;\n  rawMatches: number;\n};\n\nconst matches = matchesJson as Match[];\n\nfunction normalize(value?: string | null): string {\n  return (value ?? "")\n    .normalize("NFD")\n    .replace(/\\p{Diacritic}/gu, "")\n    .replace(/&/g, "and")\n    .replace(/[^a-zA-Z0-9]+/g, " ")\n    .trim()\n    .toLowerCase();\n}\n\nconst TEAM_ALIASES: Record<string, string[]> = {\n  "México": ["Mexico", "MEX"],\n  "Sudáfrica": ["South Africa", "RSA"],\n  "Corea del Sur": ["South Korea", "Korea Republic", "KOR"],\n  "República Checa": ["Czech Republic", "Czechia", "CZE"],\n  "Canadá": ["Canada", "CAN"],\n  "Bosnia y Herzegovina": ["Bosnia and Herzegovina", "Bosnia-Herzegovina", "Bosnia", "BIH"],\n  "Estados Unidos": ["United States", "USA", "United States of America"],\n  "Paraguay": ["Paraguay", "PAR"],\n  "Catar": ["Qatar", "QAT"],\n  "Suiza": ["Switzerland", "SUI"],\n  "Brasil": ["Brazil", "BRA"],\n  "Marruecos": ["Morocco", "MAR"],\n  "Haití": ["Haiti", "HAI"],\n  "Escocia": ["Scotland", "SCO"],\n  "Australia": ["Australia", "AUS"],\n  "Turquía": ["Turkey", "Türkiye", "Turkiye", "TUR"],\n  "Alemania": ["Germany", "GER"],\n  "Curazao": ["Curacao", "Curaçao", "CUW"],\n  "Países Bajos": ["Netherlands", "Holland", "NED"],\n  "Japón": ["Japan", "JPN"],\n  "Costa de Marfil": ["Ivory Coast", "Cote d\'Ivoire", "Côte d\'Ivoire", "CIV"],\n  "Ecuador": ["Ecuador", "ECU"],\n  "Suecia": ["Sweden", "SWE"],\n  "Túnez": ["Tunisia", "TUN"],\n  "España": ["Spain", "ESP"],\n  "Cabo Verde": ["Cape Verde", "Cabo Verde", "CPV"],\n  "Bélgica": ["Belgium", "BEL"],\n  "Egipto": ["Egypt", "EGY"],\n  "Arabia Saudí": ["Saudi Arabia", "KSA"],\n  "Uruguay": ["Uruguay", "URU"],\n  "Irán": ["Iran", "IRN"],\n  "Nueva Zelanda": ["New Zealand", "NZL"],\n  "Francia": ["France", "FRA"],\n  "Senegal": ["Senegal", "SEN"],\n  "Irak": ["Iraq", "IRQ"],\n  "Noruega": ["Norway", "NOR"],\n  "Argentina": ["Argentina", "ARG"],\n  "Argelia": ["Algeria", "ALG"],\n  "Austria": ["Austria", "AUT"],\n  "Jordania": ["Jordan", "JOR"],\n  "Portugal": ["Portugal", "POR"],\n  "RD Congo": ["DR Congo", "Congo DR", "Congo Democratic Republic", "Democratic Republic of the Congo", "COD"],\n  "Inglaterra": ["England", "ENG"],\n  "Croacia": ["Croatia", "CRO"],\n  "Ghana": ["Ghana", "GHA"],\n  "Panamá": ["Panama", "PAN"],\n  "Uzbekistán": ["Uzbekistan", "UZB"],\n  "Colombia": ["Colombia", "COL"]\n};\n\nfunction aliasesFor(team: string): string[] {\n  return [team, ...(TEAM_ALIASES[team] ?? [])].map(normalize);\n}\n\nfunction apiTeamNames(team: FootballDataMatch["homeTeam"]): string[] {\n  return [team.name, team.shortName, team.tla].filter(Boolean).map((value) => normalize(value));\n}\n\nfunction sameDate(apiDateTime: string, matchDate?: string): boolean {\n  if (!matchDate) return true;\n  return apiDateTime.slice(0, 10) === matchDate;\n}\n\nfunction matchStatus(status: string): MatchResult["status"] {\n  if (["FINISHED", "AWARDED"].includes(status)) return "FINISHED";\n  if (["IN_PLAY", "PAUSED"].includes(status)) return "LIVE";\n  return "SCHEDULED";\n}\n\nfunction intersects(a: string[], b: string[]): boolean {\n  return a.some((item) => b.includes(item));\n}\n\nfunction matchFixture(match: Match, fixture: FootballDataMatch): "direct" | "reverse" | null {\n  // Fecha ayuda, pero no la hacemos obligatoria porque los horarios UTC pueden cruzar medianoche.\n  const dateLooksClose = sameDate(fixture.utcDate, match.date);\n  const matchHomeAliases = aliasesFor(match.home);\n  const matchAwayAliases = aliasesFor(match.away);\n  const apiHomeAliases = apiTeamNames(fixture.homeTeam);\n  const apiAwayAliases = apiTeamNames(fixture.awayTeam);\n\n  const direct = intersects(matchHomeAliases, apiHomeAliases) && intersects(matchAwayAliases, apiAwayAliases);\n  const reverse = intersects(matchHomeAliases, apiAwayAliases) && intersects(matchAwayAliases, apiHomeAliases);\n\n  if (direct && dateLooksClose) return "direct";\n  if (reverse && dateLooksClose) return "reverse";\n\n  // Fallback por si football-data usa UTC y la fecha local difiere un día.\n  if (direct) return "direct";\n  if (reverse) return "reverse";\n\n  return null;\n}\n\nexport async function getFootballDataResults(): Promise<ApiResultsPayload> {\n  const token = process.env.FOOTBALL_DATA_TOKEN;\n\n  if (!token) {\n    return {\n      results: {},\n      updatedAt: new Date().toISOString(),\n      source: "football-data",\n      matchedFixtures: 0,\n      rawMatches: 0,\n      error: "Falta FOOTBALL_DATA_TOKEN en las variables de entorno."\n    };\n  }\n\n  const url = `${API_URL}?season=${SEASON}`;\n\n  try {\n    const response = await fetch(url, {\n      headers: {\n        "X-Auth-Token": token\n      },\n      next: {\n        revalidate: 60\n      }\n    });\n\n    const data = (await response.json()) as FootballDataResponse;\n\n    if (!response.ok) {\n      return {\n        results: {},\n        updatedAt: new Date().toISOString(),\n        source: "football-data",\n        matchedFixtures: 0,\n        rawMatches: data.matches?.length ?? 0,\n        error: data.message ?? `football-data respondió con HTTP ${response.status}.`\n      };\n    }\n\n    const apiMatches = data.matches ?? [];\n    const results: Record<string, MatchResult> = {};\n    let matchedFixtures = 0;\n\n    for (const match of matches) {\n      const found = apiMatches\n        .map((fixture) => ({ fixture, direction: matchFixture(match, fixture) }))\n        .find((item) => item.direction !== null);\n\n      if (!found) continue;\n\n      matchedFixtures += 1;\n\n      const { fixture, direction } = found;\n      const rawHome = direction === "direct" ? fixture.score.fullTime.home : fixture.score.fullTime.away;\n      const rawAway = direction === "direct" ? fixture.score.fullTime.away : fixture.score.fullTime.home;\n\n      if (typeof rawHome !== "number" || typeof rawAway !== "number") {\n        continue;\n      }\n\n      results[match.id] = {\n        homeGoals: rawHome,\n        awayGoals: rawAway,\n        status: matchStatus(fixture.status),\n        updatedAt: new Date().toISOString()\n      };\n    }\n\n    return {\n      results,\n      updatedAt: new Date().toISOString(),\n      source: "football-data",\n      matchedFixtures,\n      rawMatches: apiMatches.length\n    };\n  } catch (error) {\n    return {\n      results: {},\n      updatedAt: new Date().toISOString(),\n      source: "football-data",\n      matchedFixtures: 0,\n      rawMatches: 0,\n      error: error instanceof Error ? error.message : "Error desconocido consultando football-data."\n    };\n  }\n}\n',
    "lib/scoring.ts": 'import matches from "@/data/matches.json";\nimport predictions from "@/data/predictions.json";\nimport players from "@/data/players.json";\nimport type { Match, MatchResult, Pick, Prediction, ScoredPrediction, Standing } from "./types";\n\nconst allMatches = matches as Match[];\nconst allPredictions = predictions as Prediction[];\nconst allPlayers = players as string[];\n\nexport type PlayerSummary = {\n  player: string;\n  played: number;\n  correct: number;\n  wrong: number;\n  pending: number;\n};\n\nexport function signFromResult(result?: MatchResult): Pick | undefined {\n  if (!result) return undefined;\n  if (result.homeGoals > result.awayGoals) return "1";\n  if (result.homeGoals < result.awayGoals) return "2";\n  return "X";\n}\n\nexport function scorePrediction(prediction: Prediction, result?: MatchResult): number {\n  const actual = signFromResult(result);\n  if (!actual) return 0;\n  return prediction.pick === actual ? 1 : 0;\n}\n\nexport function getResults(): Record<string, MatchResult> {\n  return {};\n}\n\nexport function getMatches(): Match[] {\n  return allMatches;\n}\n\nexport function getPlayers(): string[] {\n  return allPlayers;\n}\n\nexport function getPredictions(): Prediction[] {\n  return allPredictions;\n}\n\nexport function getScoredPredictions(results: Record<string, MatchResult> = {}): ScoredPrediction[] {\n  const matchById = new Map(allMatches.map((match) => [match.id, match]));\n\n  return allPredictions.map((prediction) => {\n    const match = matchById.get(prediction.matchId);\n    if (!match) {\n      throw new Error(`Missing match ${prediction.matchId}`);\n    }\n\n    const result = results[prediction.matchId];\n    const actual = signFromResult(result);\n    const points = scorePrediction(prediction, result);\n\n    return {\n      ...prediction,\n      match,\n      result,\n      actual,\n      points,\n      isCorrect: actual ? prediction.pick === actual : null\n    };\n  });\n}\n\nexport function getStandings(results: Record<string, MatchResult> = {}): Standing[] {\n  const scored = getScoredPredictions(results);\n  const table = new Map<string, Standing>();\n\n  for (const player of allPlayers) {\n    table.set(player, {\n      player,\n      points: 0,\n      played: 0,\n      correct: 0,\n      pending: allMatches.length,\n      percentage: 0\n    });\n  }\n\n  for (const item of scored) {\n    const row = table.get(item.player);\n    if (!row) continue;\n\n    if (item.actual) {\n      row.played += 1;\n      row.pending -= 1;\n      row.points += item.points;\n      if (item.isCorrect) row.correct += 1;\n    }\n  }\n\n  return [...table.values()]\n    .map((row) => ({\n      ...row,\n      percentage: row.played > 0 ? Math.round((row.correct / row.played) * 100) : 0\n    }))\n    .sort((a, b) => {\n      if (b.points !== a.points) return b.points - a.points;\n      if (b.percentage !== a.percentage) return b.percentage - a.percentage;\n      return a.player.localeCompare(b.player, "es");\n    });\n}\n\nexport function getPlayerPredictions(\n  player: string,\n  results: Record<string, MatchResult> = {}\n): ScoredPrediction[] {\n  return getScoredPredictions(results)\n    .filter((item) => item.player.toLowerCase() === decodeURIComponent(player).toLowerCase())\n    .sort((a, b) => a.match.order - b.match.order);\n}\n\nexport function getMatchPredictions(\n  matchId: string,\n  results: Record<string, MatchResult> = {}\n): ScoredPrediction[] {\n  return getScoredPredictions(results)\n    .filter((item) => item.matchId === matchId)\n    .sort((a, b) => a.player.localeCompare(b.player, "es"));\n}\n\nexport function getPlayerSummary(\n  player: string,\n  results: Record<string, MatchResult> = {}\n): PlayerSummary {\n  const predictions = getPlayerPredictions(player, results);\n  const played = predictions.filter((item) => item.actual).length;\n  const correct = predictions.filter((item) => item.isCorrect === true).length;\n  const wrong = predictions.filter((item) => item.isCorrect === false).length;\n\n  return {\n    player,\n    played,\n    correct,\n    wrong,\n    pending: allMatches.length - played\n  };\n}\n\nexport function getPlayerSummaries(results: Record<string, MatchResult> = {}): PlayerSummary[] {\n  return allPlayers.map((player) => getPlayerSummary(player, results));\n}\n',
    "lib/types.ts": 'export type Pick = "1" | "X" | "2";\n\nexport type Match = {\n  id: string;\n  home: string;\n  away: string;\n  label: string;\n  order: number;\n  group?: string;\n  date?: string;\n  timeLocal?: string;\n  timeEt?: string;\n  city?: string;\n  stadium?: string;\n};\n\nexport type Prediction = {\n  matchId: string;\n  player: string;\n  pick: Pick;\n};\n\nexport type MatchResult = {\n  homeGoals: number;\n  awayGoals: number;\n  status?: "SCHEDULED" | "LIVE" | "FINISHED";\n  minute?: number;\n  updatedAt?: string;\n};\n\nexport type ScoredPrediction = Prediction & {\n  match: Match;\n  result?: MatchResult;\n  actual?: Pick;\n  points: number;\n  isCorrect: boolean | null;\n};\n\nexport type Standing = {\n  player: string;\n  points: number;\n  played: number;\n  correct: number;\n  pending: number;\n  percentage: number;\n};\n',
    "app/api/results/route.ts": 'import { NextResponse } from "next/server";\nimport { getFootballDataResults } from "@/lib/footballData";\n\nexport const dynamic = "force-dynamic";\n\nexport async function GET() {\n  const payload = await getFootballDataResults();\n  return NextResponse.json(payload);\n}\n',
    "app/page.tsx": 'import { StandingCard } from "@/components/StandingCard";\nimport { getFootballDataResults } from "@/lib/footballData";\nimport { getMatches, getStandings } from "@/lib/scoring";\n\nexport const dynamic = "force-dynamic";\n\nexport default async function HomePage() {\n  const payload = await getFootballDataResults();\n  const standings = getStandings(payload.results);\n  const played = Object.keys(payload.results).length;\n  const total = getMatches().length;\n\n  return (\n    <section>\n      <div className="hero">\n        <div className="kicker">Mundial 2026</div>\n        <h1>Porra primera fase</h1>\n        <p>\n          {played}/{total} partidos puntuados\n          {payload.error ? " · API pendiente" : ""}\n        </p>\n      </div>\n\n      <div className="section-title">\n        <h2>Clasificación</h2>\n        <span>1 punto por signo acertado</span>\n      </div>\n\n      <div className="stack">\n        {standings.map((row, index) => (\n          <StandingCard key={row.player} row={row} position={index + 1} />\n        ))}\n      </div>\n    </section>\n  );\n}\n',
    "app/partidos/page.tsx": 'import { MatchCard } from "@/components/MatchCard";\nimport { formatLongMatchDate } from "@/lib/format";\nimport { getFootballDataResults } from "@/lib/footballData";\nimport { getMatches } from "@/lib/scoring";\n\nexport const dynamic = "force-dynamic";\n\nexport default async function MatchesPage() {\n  const matches = getMatches();\n  const payload = await getFootballDataResults();\n\n  const grouped = matches.reduce((acc, match) => {\n    const key = match.date ?? "Fecha pendiente";\n    if (!acc[key]) acc[key] = [];\n    acc[key].push(match);\n    return acc;\n  }, {} as Record<string, typeof matches>);\n\n  return (\n    <section>\n      <div className="page-header">\n        <h1>Partidos</h1>\n        <p>\n          Fecha, grupo, horario local, horario español y pronósticos de la porra.\n          {payload.error ? " La API todavía no está devolviendo resultados." : ""}\n        </p>\n      </div>\n\n      <div className="date-stack">\n        {Object.entries(grouped).map(([date, dayMatches]) => (\n          <section key={date} className="date-section">\n            <h2>{formatLongMatchDate(date)}</h2>\n            <div className="stack">\n              {dayMatches.map((match) => (\n                <MatchCard key={match.id} match={match} result={payload.results[match.id]} />\n              ))}\n            </div>\n          </section>\n        ))}\n      </div>\n    </section>\n  );\n}\n',
    "app/pronosticos/page.tsx": 'import Link from "next/link";\nimport { normalizePlayerForUrl } from "@/lib/format";\nimport { getFootballDataResults } from "@/lib/footballData";\nimport { getPlayerSummaries } from "@/lib/scoring";\n\nexport const dynamic = "force-dynamic";\n\nexport default async function PredictionsPage() {\n  const payload = await getFootballDataResults();\n  const players = getPlayerSummaries(payload.results);\n\n  return (\n    <section>\n      <div className="page-header">\n        <h1>Pronósticos</h1>\n        <p>La quiniela individual de cada jugador.</p>\n      </div>\n\n      <div className="grid-list">\n        {players.map((row) => (\n          <Link key={row.player} href={`/pronosticos/${normalizePlayerForUrl(row.player)}`} className="player-tile">\n            <span>{row.player}</span>\n            <div className="pronostic-summary">\n              {row.played === 0 ? (\n                <>Ver quiniela</>\n              ) : (\n                <>{row.correct} aciertos · {row.wrong} fallos</>\n              )}\n            </div>\n          </Link>\n        ))}\n      </div>\n    </section>\n  );\n}\n',
    "app/pronosticos/[player]/page.tsx": 'import Link from "next/link";\nimport { notFound } from "next/navigation";\nimport { formatMatchDate, resultLabel } from "@/lib/format";\nimport { getFootballDataResults } from "@/lib/footballData";\nimport { getPlayerPredictions, getPlayerSummary, getPlayers } from "@/lib/scoring";\n\nexport const dynamic = "force-dynamic";\n\nexport function generateStaticParams() {\n  return getPlayers().map((player) => ({ player }));\n}\n\nexport default async function PlayerPredictionPage({\n  params,\n}: {\n  params: Promise<{ player: string }>;\n}) {\n  const { player: rawPlayer } = await params;\n  const player = decodeURIComponent(rawPlayer);\n\n  const payload = await getFootballDataResults();\n  const predictions = getPlayerPredictions(player, payload.results);\n  if (predictions.length === 0) notFound();\n\n  const summary = getPlayerSummary(player, payload.results);\n\n  return (\n    <section>\n      <div className="page-header">\n        <Link href="/pronosticos" className="back">← Pronósticos</Link>\n        <h1>{player}</h1>\n        <p>\n          {summary.played === 0\n            ? "Quiniela completa"\n            : `${summary.correct} aciertos · ${summary.wrong} fallos · ${summary.pending} pendientes`}\n        </p>\n      </div>\n\n      <div className="stack">\n        {predictions.map((item) => (\n          <article key={item.matchId} className="prediction-card">\n            <div>\n              <div className="meta-row">\n                <span>{formatMatchDate(item.match.date)}</span>\n                <span className="group-chip">Grupo {item.match.group ?? "—"}</span>\n              </div>\n              <div className="match-label">{item.match.label}</div>\n              <div className="muted">Resultado: {resultLabel(payload.results[item.matchId])}</div>\n            </div>\n            <div className="prediction-right">\n              <span className="chip">{item.pick}</span>\n              {item.isCorrect === null ? (\n                <span className="pill pending">Pendiente</span>\n              ) : item.isCorrect ? (\n                <span className="pill ok">+1</span>\n              ) : (\n                <span className="pill ko">0</span>\n              )}\n            </div>\n          </article>\n        ))}\n      </div>\n    </section>\n  );\n}\n',
    "app/admin/page.tsx": 'import { getFootballDataResults } from "@/lib/footballData";\n\nexport const dynamic = "force-dynamic";\n\nexport default async function AdminPage() {\n  const payload = await getFootballDataResults();\n\n  return (\n    <section>\n      <div className="page-header">\n        <h1>Estado API</h1>\n        <p>Pantalla oculta para comprobar si football-data.org está respondiendo.</p>\n      </div>\n\n      <div className="code-card">\n        <p>Fuente: {payload.source}</p>\n        <p>Partidos recibidos de API: {payload.rawMatches}</p>\n        <p>Partidos emparejados: {payload.matchedFixtures}</p>\n        <p>Resultados con marcador: {Object.keys(payload.results).length}</p>\n        <p>Última actualización: {payload.updatedAt}</p>\n        {payload.error ? <p>Error: {payload.error}</p> : null}\n      </div>\n\n      <div className="code-card">\n        <p>Respuesta resumida:</p>\n        <pre>{JSON.stringify(payload, null, 2)}</pre>\n      </div>\n    </section>\n  );\n}\n',
}

for rel, content in files.items():
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")

gitignore = ROOT / ".gitignore"
existing = gitignore.read_text(encoding="utf-8") if gitignore.exists() else ""
if ".env.local" not in existing:
    gitignore.write_text(existing.rstrip() + "\n\n.env.local\n.env\n", encoding="utf-8")

print("Versión football-data aplicada. Usa FOOTBALL_DATA_TOKEN como variable de entorno.")
